import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  // Map weather conditions to emojis
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloud')) return '☁️';
    if (condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm')) return '⛈️';
    if (condLower.includes('wind')) return '💨';
    if (condLower.includes('fog')) return '🌫️';
    return '🌡️';
  };

  const currentWeatherEmoji = getWeatherEmoji(condition);
  const currentWeatherStyle = {
    fontSize: 'var(--ggui-font-size-4xl, 36px)',
    lineHeight: '1',
    marginBottom: 'var(--ggui-spacing-2, 8px)',
  };

  const temperatureStyle = {
    fontSize: 'var(--ggui-font-size-4xl, 36px)',
    fontWeight: 'var(--ggui-font-weight-bold, 700)',
    color: 'var(--ggui-color-primary-600, #0284c7)',
    lineHeight: '1.2',
  };

  const cityStyle = {
    fontSize: 'var(--ggui-font-size-lg, 18px)',
    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
    color: 'var(--ggui-color-neutral-900, #111827)',
    marginBottom: 'var(--ggui-spacing-4, 16px)',
  };

  const conditionStyle = {
    fontSize: 'var(--ggui-font-size-base, 16px)',
    color: 'var(--ggui-color-neutral-600, #4b5563)',
    marginBottom: 'var(--ggui-spacing-4, 16px)',
  };

  const detailLabelStyle = {
    fontSize: 'var(--ggui-font-size-sm, 14px)',
    color: 'var(--ggui-color-neutral-500, #6b7280)',
    fontWeight: 'var(--ggui-font-weight-normal, 400)',
  };

  const detailValueStyle = {
    fontSize: 'var(--ggui-font-size-base, 16px)',
    color: 'var(--ggui-color-neutral-700, #374151)',
    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
  };

  const forecastDayStyle = {
    fontSize: 'var(--ggui-font-size-sm, 14px)',
    fontWeight: 'var(--ggui-font-weight-medium, 500)',
    color: 'var(--ggui-color-neutral-700, #374151)',
  };

  const forecastEmojiStyle = {
    fontSize: 'var(--ggui-font-size-xl, 20px)',
    lineHeight: '1',
    margin: 'var(--ggui-spacing-2, 8px) 0',
  };

  const forecastTempStyle = {
    fontSize: 'var(--ggui-font-size-xs, 12px)',
    color: 'var(--ggui-color-neutral-600, #4b5563)',
  };

  const forecastHighStyle = {
    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
  };

  const dividerStyle = {
    height: '1px',
    backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
    margin: `var(--ggui-spacing-4, 16px) 0`,
  };

  const forecastContainerStyle = {
    padding: `var(--ggui-spacing-4, 16px) 0`,
    display: 'flex',
    gap: 'var(--ggui-spacing-2, 8px)',
    overflowX: 'auto' as const,
  };

  const forecastItemStyle = {
    flex: '0 0 auto',
    minWidth: '80px',
    textAlign: 'center' as const,
    padding: 'var(--ggui-spacing-3, 12px)',
    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
  };

  return (
    <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
      <Stack direction="vertical" gap={0}>
        {/* Header - City Name */}
        <div style={cityStyle}>{city}</div>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={16} align="center" justify="start">
          <div>
            <div style={currentWeatherStyle}>{currentWeatherEmoji}</div>
            <div style={temperatureStyle}>
              {temperature}°{unit}
            </div>
          </div>
          <Stack direction="vertical" gap={8} justify="center">
            <div style={conditionStyle}>{condition}</div>
            <Row gap={24}>
              <Stack direction="vertical" gap={4}>
                <div style={detailLabelStyle}>Humidity</div>
                <div style={detailValueStyle}>{humidity}%</div>
              </Stack>
              <Stack direction="vertical" gap={4}>
                <div style={detailLabelStyle}>Wind Speed</div>
                <div style={detailValueStyle}>{windSpeed} {unit === 'C' ? 'km/h' : 'mph'}</div>
              </Stack>
            </Row>
          </Stack>
        </Stack>

        {/* Divider */}
        <div style={dividerStyle} />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={8}>
          <div style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', fontWeight: 'var(--ggui-font-weight-semibold, 600)', color: 'var(--ggui-color-neutral-700, #374151)' }}>
            5-Day Forecast
          </div>
          <div style={forecastContainerStyle}>
            {forecast.map((item, index) => (
              <div key={index} style={forecastItemStyle}>
                <div style={forecastDayStyle}>{item.day}</div>
                <div style={forecastEmojiStyle}>{item.icon}</div>
                <div style={forecastTempStyle}>
                  <span style={forecastHighStyle}>{item.high}°</span>
                  <span style={{ marginLeft: 'var(--ggui-spacing-1, 4px)' }}>
                    {item.low}°
                  </span>
                </div>
              </div>
            ))}
          </div>
        </Stack>
      </Stack>
    </Card>
  );
}
